1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	function isComponentBlock(items: any[]): boolean {
14	  return items.length === 3 && items.every((i) => i.type === items[0].type);
15	}
16	
17	const COMPONENT_BLOCK_PREMIUM: Record<string, number> = {
18	  rune: 60,
19	};
20	
21	function calculateBasePremium(items: any[]): number {
22	  if (isComponentBlock(items)) {
23	    return COMPONENT_BLOCK_PREMIUM[items[0].type];
24	  }
25	  return items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
26	}
27	
28	function calculatePremium(items: any[]): number {
29	  const basePremium = calculateBasePremium(items);
30	  return Math.ceil(basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE);
31	}
32	
33	export function processScenario(scenario: any): unknown {
34	  const { items } = scenario.steps[0];
35	  const premium = calculatePremium(items);
36	
37	  return { results: [{ premium }] };
38	}
